package main

import (
	"encoding/gob"
	"fmt"
	"os"
	"sync"
)

type UserSession struct {
	UserID      string
	Preferences map[string]string
	Permissions  []string
}

type SessionManager struct {
	sessions map[string]*UserSession
	mu       sync.Mutex
}

func NewSessionManager() *SessionManager {
	return &SessionManager{
		sessions: make(map[string]*UserSession),
	}
}

func (sm *SessionManager) SaveSession(userID string, session *UserSession) error {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	file, err := os.Create(userID + ".session")
	if err != nil {
		return err
	}
	defer file.Close()

	encoder := gob.NewEncoder(file)
	return encoder.Encode(session)
}

func (sm *SessionManager) LoadSession(userID string) (*UserSession, error) {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	file, err := os.Open(userID + ".session")
	if err != nil {
		return nil, err
	}
	defer file.Close()

	var session UserSession
	decoder := gob.NewDecoder(file)
	if err := decoder.Decode(&session); err != nil {
		return nil, err
	}
	return &session, nil
}

func main() {
	sm := NewSessionManager()

	session := &UserSession{
		UserID:      "user123",
		Preferences: map[string]string{"theme": "dark"},
		Permissions:  []string{"read", "write"},
	}

	if err := sm.SaveSession(session.UserID, session); err != nil {
		fmt.Println("Error saving session:", err)
		return
	}

	loadedSession, err := sm.LoadSession(session.UserID)
	if err != nil {
		fmt.Println("Error loading session:", err)
		return
	}

	fmt.Println("Loaded session:", loadedSession)
}